"use client";

import * as React from "react";
import {
  Badge,
  Button,
  Calendar,
  Card,
  CardContent,
  CardDescription,
  CardHeader,
  CardTitle,
  Container,
  Form,
  FormDescription,
  FormField,
  FormGroup,
  FormLabel,
  FormMessage,
  Input,
  Select,
  Separator,
} from "@gunjo/ui";

// ---------------------------------------------------------------------------
// Static booking domain data (would normally come from an API).
// ---------------------------------------------------------------------------

type Service = {
  id: string;
  name: string;
  durationMin: number;
  price: number;
};

const SERVICES: Service[] = [
  { id: "consult", name: "初回カウンセリング", durationMin: 30, price: 0 },
  { id: "haircut", name: "カット＆スタイリング", durationMin: 60, price: 6500 },
  { id: "color", name: "フルカラー", durationMin: 120, price: 14000 },
  { id: "treatment", name: "スカルプトリートメント", durationMin: 45, price: 5000 },
];

// All bookable slots for a day (24h "HH:mm").
const ALL_SLOTS = [
  "09:00",
  "09:30",
  "10:00",
  "10:30",
  "11:00",
  "11:30",
  "13:00",
  "13:30",
  "14:00",
  "14:30",
  "15:00",
  "15:30",
  "16:00",
  "16:30",
];

// ---------------------------------------------------------------------------
// Date helpers. We keep everything in local time and only ever compare /
// format on the client to avoid SSR/locale hydration drift.
// ---------------------------------------------------------------------------

function startOfDay(date: Date): Date {
  return new Date(date.getFullYear(), date.getMonth(), date.getDate());
}

function dateKey(date: Date): string {
  // Local YYYY-MM-DD — stable key for lookups, never rendered.
  const y = date.getFullYear();
  const m = String(date.getMonth() + 1).padStart(2, "0");
  const d = String(date.getDate()).padStart(2, "0");
  return `${y}-${m}-${d}`;
}

function addDays(date: Date, days: number): Date {
  const next = new Date(date);
  next.setDate(next.getDate() + days);
  return next;
}

// Pretend availability: 2 and 4 days from "today" are fully booked / closed.
function getUnavailableDates(today: Date): Date[] {
  return [addDays(today, 2), addDays(today, 4)];
}

// Pretend slot availability: a couple of slots are already taken per day,
// deterministically derived from the date so it is SSR-stable.
function getTakenSlots(date: Date): Set<string> {
  const seed = date.getDate();
  const taken = new Set<string>();
  if (seed % 2 === 0) {
    taken.add("10:00");
    taken.add("14:30");
  } else {
    taken.add("11:00");
    taken.add("15:00");
  }
  return taken;
}

function yen(value: number): string {
  return value === 0 ? "無料" : `¥${value.toLocaleString("en-US")}`;
}

const EMAIL_RE = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;

export default function BookingPage() {
  // `null` until mounted: we resolve "today" on the client only, so the
  // calendar's disabled-before matcher never differs between server & client.
  const [today, setToday] = React.useState<Date | null>(null);

  const [selectedDate, setSelectedDate] = React.useState<Date | undefined>(
    undefined
  );
  const [selectedSlot, setSelectedSlot] = React.useState<string | undefined>(
    undefined
  );
  const [serviceId, setServiceId] = React.useState<string>(SERVICES[0].id);
  const [name, setName] = React.useState("");
  const [email, setEmail] = React.useState("");
  const [submitted, setSubmitted] = React.useState(false);

  React.useEffect(() => {
    setToday(startOfDay(new Date()));
  }, []);

  const unavailableDates = React.useMemo(
    () => (today ? getUnavailableDates(today) : []),
    [today]
  );

  const unavailableKeys = React.useMemo(
    () => new Set(unavailableDates.map(dateKey)),
    [unavailableDates]
  );

  const takenSlots = React.useMemo(
    () => (selectedDate ? getTakenSlots(selectedDate) : new Set<string>()),
    [selectedDate]
  );

  const service = SERVICES.find((s) => s.id === serviceId)!;

  // Long-form, locale-explicit date label (client-only render path).
  const dateLabel = selectedDate
    ? selectedDate.toLocaleDateString("ja-JP", {
        weekday: "long",
        year: "numeric",
        month: "long",
        day: "numeric",
      })
    : null;

  const emailValid = email === "" || EMAIL_RE.test(email);
  const canConfirm =
    !!selectedDate &&
    !!selectedSlot &&
    name.trim().length > 0 &&
    EMAIL_RE.test(email);

  function handleSelectDate(date: Date | undefined) {
    setSelectedDate(date);
    setSelectedSlot(undefined); // slots depend on the date
    setSubmitted(false);
  }

  function handleConfirm(event: React.FormEvent) {
    event.preventDefault();
    if (!canConfirm) return;
    setSubmitted(true);
  }

  return (
    <Container className="max-w-5xl py-10">
      <header className="mb-8 flex flex-col gap-1">
        <h1 className="text-3xl font-semibold tracking-tight text-foreground">
          ご予約
        </h1>
        <p className="text-sm text-muted-foreground">
          日時とメニューを選び、お客様情報をご確認のうえご予約ください。
        </p>
      </header>

      <div className="grid grid-cols-1 gap-6 lg:grid-cols-[minmax(0,1fr)_360px]">
        {/* ----------------------------------------------------------------- */}
        {/* Left column: date + time + service + form                         */}
        {/* ----------------------------------------------------------------- */}
        <div className="flex flex-col gap-6">
          {/* Step 1 — date */}
          <Card>
            <CardHeader>
              <CardTitle className="text-xl">1. 日付を選択</CardTitle>
              <CardDescription>
                過去の日付は選択できません。グレーの日は満席です。
              </CardDescription>
            </CardHeader>
            <CardContent>
              {today ? (
                <Calendar
                  mode="single"
                  selected={selectedDate}
                  onSelect={handleSelectDate}
                  startMonth={today}
                  disabled={[
                    { before: today },
                    ...unavailableDates,
                    { dayOfWeek: [0] }, // closed Sundays
                  ]}
                  getDisabledReason={(date) => {
                    if (date < today) return "過去の日付は選択できません。";
                    if (date.getDay() === 0) return "日曜日は定休日です。";
                    if (unavailableKeys.has(dateKey(date)))
                      return "満席のため予約できません。";
                    return "予約できません。";
                  }}
                  className="mx-auto"
                />
              ) : (
                // Stable placeholder for first paint — avoids resolving
                // `new Date()` during SSR and hydrating a different month.
                <div
                  className="mx-auto h-[360px] w-[320px] max-w-full animate-pulse rounded-lg border bg-muted/40"
                  aria-hidden
                />
              )}
            </CardContent>
          </Card>

          {/* Step 2 — time slot */}
          <Card>
            <CardHeader>
              <CardTitle className="text-xl">2. 時間を選択</CardTitle>
              <CardDescription>
                {selectedDate
                  ? "グレーの時間帯はすでに予約済みです。"
                  : "まず日付を選択すると、空き時間が表示されます。"}
              </CardDescription>
            </CardHeader>
            <CardContent>
              {selectedDate ? (
                <div
                  className="grid grid-cols-3 gap-2 sm:grid-cols-4"
                  role="group"
                  aria-label="予約可能な時間帯"
                >
                  {ALL_SLOTS.map((slot) => {
                    const taken = takenSlots.has(slot);
                    const active = selectedSlot === slot;
                    return (
                      <Button
                        key={slot}
                        type="button"
                        variant={active ? "primary" : "outline"}
                        size="sm"
                        disabled={taken}
                        aria-pressed={active}
                        aria-label={
                          taken ? `${slot} — 予約済み` : `${slot}`
                        }
                        onClick={() => {
                          setSelectedSlot(slot);
                          setSubmitted(false);
                        }}
                        className="w-full"
                      >
                        {slot}
                      </Button>
                    );
                  })}
                </div>
              ) : (
                <p className="text-sm text-muted-foreground">
                  まだ日付が選択されていません。
                </p>
              )}
            </CardContent>
          </Card>

          {/* Step 3 — service + contact form */}
          <Card>
            <CardHeader>
              <CardTitle className="text-xl">3. お客様情報</CardTitle>
              <CardDescription>
                メニューを選び、お客様情報をご入力ください。
              </CardDescription>
            </CardHeader>
            <CardContent>
              <Form onSubmit={handleConfirm} id="booking-form">
                <FormGroup>
                  <FormField className="p-0">
                    <FormLabel htmlFor="service">メニュー</FormLabel>
                    <Select
                      id="service"
                      value={serviceId}
                      onChange={(e) => {
                        setServiceId(e.target.value);
                        setSubmitted(false);
                      }}
                    >
                      {SERVICES.map((s) => (
                        <option key={s.id} value={s.id}>
                          {s.name} · {s.durationMin}分 · {yen(s.price)}
                        </option>
                      ))}
                    </Select>
                    <FormDescription>
                      所要時間: {service.durationMin}分
                    </FormDescription>
                  </FormField>

                  <FormField className="p-0">
                    <FormLabel htmlFor="name">お名前</FormLabel>
                    <Input
                      id="name"
                      value={name}
                      onChange={(e) => {
                        setName(e.target.value);
                        setSubmitted(false);
                      }}
                      placeholder="山田 花子"
                      autoComplete="name"
                    />
                  </FormField>

                  <FormField className="p-0">
                    <FormLabel htmlFor="email">メールアドレス</FormLabel>
                    <Input
                      id="email"
                      type="email"
                      value={email}
                      onChange={(e) => {
                        setEmail(e.target.value);
                        setSubmitted(false);
                      }}
                      placeholder="hanako@example.com"
                      autoComplete="email"
                      aria-invalid={!emailValid || undefined}
                    />
                    {!emailValid ? (
                      <FormMessage>
                        有効なメールアドレスを入力してください。
                      </FormMessage>
                    ) : null}
                  </FormField>
                </FormGroup>
              </Form>
            </CardContent>
          </Card>
        </div>

        {/* ----------------------------------------------------------------- */}
        {/* Right column: sticky summary                                      */}
        {/* ----------------------------------------------------------------- */}
        <div className="lg:sticky lg:top-6 lg:self-start">
          <Card>
            <CardHeader>
              <CardTitle className="text-xl">予約内容</CardTitle>
              <CardDescription>ご確認のうえご予約ください。</CardDescription>
            </CardHeader>
            <CardContent className="flex flex-col gap-4">
              <SummaryRow label="メニュー">
                <span className="font-medium text-foreground">
                  {service.name}
                </span>
              </SummaryRow>
              <SummaryRow label="所要時間">
                <Badge variant="secondary">{service.durationMin}分</Badge>
              </SummaryRow>
              <SummaryRow label="料金">
                <span className="font-medium text-foreground">
                  {yen(service.price)}
                </span>
              </SummaryRow>

              <Separator />

              <SummaryRow label="日付">
                {dateLabel ? (
                  <span className="text-right font-medium text-foreground">
                    {dateLabel}
                  </span>
                ) : (
                  <span className="text-muted-foreground">未選択</span>
                )}
              </SummaryRow>
              <SummaryRow label="時間">
                {selectedSlot ? (
                  <Badge variant="default">{selectedSlot}</Badge>
                ) : (
                  <span className="text-muted-foreground">未選択</span>
                )}
              </SummaryRow>

              <Separator />

              <SummaryRow label="お名前">
                {name.trim() ? (
                  <span className="text-right font-medium text-foreground">
                    {name}
                  </span>
                ) : (
                  <span className="text-muted-foreground">—</span>
                )}
              </SummaryRow>
              <SummaryRow label="メールアドレス">
                {email.trim() ? (
                  <span className="break-all text-right font-medium text-foreground">
                    {email}
                  </span>
                ) : (
                  <span className="text-muted-foreground">—</span>
                )}
              </SummaryRow>

              <Separator />

              {submitted ? (
                <div
                  className="flex flex-col gap-2 rounded-lg border border-success-border bg-success px-4 py-3 text-success-foreground"
                  role="status"
                >
                  <span className="font-semibold">ご予約を承りました</span>
                  <span className="text-sm">
                    {dateLabel} {selectedSlot} に{service.name}のご予約を承りました。確認メールを {email} にお送りしました。
                  </span>
                </div>
              ) : (
                <Button
                  type="submit"
                  form="booking-form"
                  variant="primary"
                  disabled={!canConfirm}
                  className="w-full"
                >
                  予約を確定する
                </Button>
              )}

              {!canConfirm && !submitted ? (
                <p className="text-xs text-muted-foreground">
                  ご予約には、日付・時間の選択と、お名前・有効なメールアドレスのご入力が必要です。
                </p>
              ) : null}
            </CardContent>
          </Card>
        </div>
      </div>
    </Container>
  );
}

function SummaryRow({
  label,
  children,
}: {
  label: string;
  children: React.ReactNode;
}) {
  return (
    <div className="flex items-start justify-between gap-4 text-sm">
      <span className="text-muted-foreground">{label}</span>
      {children}
    </div>
  );
}
